// 웹훅에서 받은 데이터
const { iid, phase, imageId, text, buttonText, buttonUrl } = $input.first().json.body;

// 타겟 SQL: 멤버십 전체 - 신청자 - 수신거부
const targetSql = `
WITH applicants AS (
  SELECT DISTINCT u_phone FROM purchase WHERE iid = '${iid}' AND p_cancel_amount = 0
  UNION
  SELECT DISTINCT u_phone FROM event WHERE iid = '${iid}'
)
SELECT m.u_name, m.u_phone
FROM member m
WHERE m.u_membership_tf = true
  AND m.u_marketing_agree_tf = true
  AND m.u_phone IS NOT NULL
  AND m.u_name NOT ILIKE '%테스트%'
  AND m.u_phone NOT IN (SELECT u_phone FROM applicants WHERE u_phone IS NOT NULL)
ORDER BY m.u_name
`;

return [{ json: { iid, phase, imageId, text, buttonText, buttonUrl, targetSql } }];

const items = $input.all();
const count = items.length;
const d = $('Code: 데이터 준비').first().json;

const cb = JSON.stringify({
  iid: d.iid, phase: d.phase, imageId: d.imageId,
  text: d.text, buttonText: d.buttonText, buttonUrl: d.buttonUrl
});

const blocks = [
  { type: "header", text: { type: "plain_text", text: `📢 [카플친 ${d.phase}] 발송 예정` }},
  { type: "section", text: { type: "mrkdwn", text: `*대상:* ${count}명\n*Phase:* ${d.phase}\n*이미지:* ${d.imageId ? "✅ 업로드됨" : "❌ 없음"}\n*버튼:* ${d.buttonText} → ${d.buttonUrl}` }},
  { type: "divider" },
  { type: "section", text: { type: "mrkdwn", text: `📋 *카피 미리보기:*\n\`\`\`\n${d.text || "(텍스트 없음)"}\n\`\`\`` }},
  { type: "divider" },
  { type: "context", elements: [{ type: "mrkdwn", text: "⚠️ *승인 시 즉시 발송됩니다.* 대상자 수와 내용을 반드시 확인해주세요." }]},
  { type: "actions", elements: [
    { type: "button", text: { type: "plain_text", text: "✅ 발송" }, style: "primary", action_id: "kakaoplus_approve", value: cb },
    { type: "button", text: { type: "plain_text", text: "❌ 취소" }, style: "danger", action_id: "kakaoplus_reject", value: cb }
  ]}
];

const slackBody = {
  channel: "C0AN2NZ4L7L",
  text: `[카플친 ${d.phase}] ${count}명 발송 예정`,
  blocks: JSON.stringify(blocks)
};

return [{ json: { slackBody } }];

const payloadStr = $input.first().json.body?.payload;
if (!payloadStr) return [{ json: { action: "unknown" } }];
const payload = JSON.parse(payloadStr);

const act = payload.actions?.[0];
const cb = JSON.parse(act?.value || "{}");
const base = { ch: payload.channel?.id, ts: payload.message?.ts, user: payload.user?.name, ...cb };

if (act?.action_id === "kakaoplus_reject") {
  return [{ json: { action: "reject", ...base } }];
}
if (act?.action_id === "kakaoplus_approve") {
  return [{ json: { action: "approve", ...base } }];
}
return [{ json: { action: "unknown" } }];

const crypto = require("crypto");
const https = require("https");

const API_KEY = "NCST_REDACTED_KEY";
const API_SECRET = process.env.SOLAPI_API_SECRET || "";
const PF_ID = "KA01PF_REDACTED_PFID";

const cb = $('Code: 승인 파싱').first().json;
const targets = $input.all().map(i => i.json);

function getAuth() {
  const date = new Date().toISOString();
  const salt = crypto.randomBytes(32).toString("hex");
  const sig = crypto.createHmac("sha256", API_SECRET).update(date + salt).digest("hex");
  return `HMAC-SHA256 apiKey=${API_KEY}, date=${date}, salt=${salt}, signature=${sig}`;
}

function send(body) {
  return new Promise((resolve, reject) => {
    const data = JSON.stringify(body);
    const req = https.request({
      hostname: "api.solapi.com",
      path: "/messages/v4/send-many/detail",
      method: "POST",
      headers: { Authorization: getAuth(), "Content-Type": "application/json" }
    }, res => {
      let d = "";
      res.on("data", c => d += c);
      res.on("end", () => resolve(JSON.parse(d)));
    });
    req.on("error", reject);
    req.write(data);
    req.end();
  });
}

// Batch send (50 per batch)
const results = [];
for (let i = 0; i < targets.length; i += 50) {
  const batch = targets.slice(i, i + 50);
  const messages = batch.map(t => ({
    to: t.u_phone,
    from: "15886864",
    text: cb.text || "셀피쉬클럽 이기적공유회 안내",
    kakaoOptions: {
      pfId: PF_ID,
      imageId: cb.imageId,
      disableSms: true,
      buttons: [{
        buttonType: "WL",
        buttonName: cb.buttonText || "신청하기",
        linkMo: cb.buttonUrl || "https://www.selfishclub.xyz",
        linkPc: cb.buttonUrl || "https://www.selfishclub.xyz"
      }]
    }
  }));
  const res = await send({ messages });
  results.push({ batch: i/50+1, count: batch.length, result: res });
}

return [{ json: { totalSent: targets.length, batches: results.length, results } }];
